mapper.select:
SELECT
t.*
FROM
kb_warehouse_auth t
WHERE
is_deleted = 2

    AND t.id like concat('%',#{kbWarehouseAuthEntity.id},'%')


    AND t.wh_id = #{kbWarehouseAuthEntity.whId}


    AND t.category = #{kbWarehouseAuthEntity.category}


    AND t.user_id like concat('%',#{kbWarehouseAuthEntity.userId},'%')


    AND t.wh_auth = #{kbWarehouseAuthEntity.whAuth}


    AND t.kb_auth = #{kbWarehouseAuthEntity.kbAuth}


    limit #{map.offset},#{map.rows}

mapper.update:
update kb_warehouse_auth
set is_deleted =1
where wh_id = #{wid}

mapper.select:
select distinct wh_id
from kb_warehouse_auth au
left join kb_groups_user groupb on groupb.group_id = au.user_id and status = 2
left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) and au.status = 3
join castle_sys_user user on (user.dept_id = dept.id) or (au.user_id = user.id) or (groupb.user_id = user.id)
where au.is_deleted = 2
and user.id = #{uid}


    and category = #{cateGory}


    and wh_id = #{swId}

select au.*
from kb_category ct,
kb_warehouse_auth au,
kb_subject_warehouse sw
where sw.id = ct.sw_id
and au.wh_id =ct.id
and au.user_id=#{uid}

and sw.id=#{whId}

    and au.wh_id=#{wcId}

select distinct ct.id from kb_category ct left join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01) or (ct.sw_id = au.wh_id and au.category = 02)) left join kb_groups_user groupb on groupb.group_id = au.user_id and au.status = 2 left join castle_sys_dept dept on(dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) and au.status = 3 left join castle_sys_user user on (user.dept_id = dept.id) or (au.user_id = user.id) or (groupb.user_id = user.id) where ct.is_deleted = 2 and user.is_deleted = 2 and user.id=#{uid} and kb_auth in (
#{kb_auth}
